import { GoogleGenAI, Type } from "@google/genai";
import { TripFormData, Itinerary, TravelMode, MarketInsight, GroundingSource, Stop } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// Integrated from real-keywords-collector/keywords.txt
const KEYWORD_MARKET_DATA = `
TARGET NICHE KEYWORDS (Use these for Search Validation):
- gay massage, sensual massage, erotic massage
- male massage therapist, male massage near me, gay massage therapist
- male body massage, massage male to male, male massage therapy
- gay friendly massage, gay spa massage, LGBTQ massage therapist
- massage for gay men, man on man massage, LGBTQ friendly massage
- gay deep tissue massage, gay couples massage, gay sports massage
- male to male massage therapy, gay Swedish massage
- professional male massage, male aromatherapy massage
- gay Thai massage, certified male massage therapist
`;

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const mandatoryStopsText = data.mandatoryStops
    .map(s => `${s.location}${s.arrivalDate ? ` (Arrive: ${s.arrivalDate})` : ''}`)
    .join(', ');

  const prompt = `
    TODAY'S DATE: ${today}
    ROLE: You are a specialized Logistics & Market Analyst for the male wellness sector.

    GOAL: Create a high-revenue road trip itinerary from ${data.origin} to ${data.destination}${data.destinationDate ? ` (Arrival by: ${data.destinationDate})` : ''}.

    CONSTRAINTS:
    - Max Drive: ${data.maxDriveHours} hours per leg.
    - Mandatory Stops: ${mandatoryStopsText || 'None'}.
    - Total Stops: Approx ${data.numberOfStops}.
    - Strategy: ${isAlternative ? 'Explore high-growth secondary markets (blue ocean strategy).' : 'Stick to established high-volume hubs (red ocean strategy).'}

    ${KEYWORD_MARKET_DATA}

    STRICT RULES FOR 'nightsToStay' (Classificação Final Definitiva):
    - **Score 90-100 (Platinum)**: 3 Nights.
    - **Score 75-89 (Gold)**: 2 Nights.
    - **Score 60-74 (Silver)**: 1 Night.
    - **Score < 60 (Bronze)**: 0 Nights (Day stop / Lunch only).
    - **Safety Override**: If search indicates active safety risks for LGBTQ+ travelers in the area, force 'nightsToStay' = 0.

    EXECUTION STEPS:
    1. **Route Logic**: Plan a feasible driving route.
    2. **Market Validation**: Use Google Search to check demand in intermediate cities.
    3. **Evidence-Based Justification**: Cite specific events/venues.
  `;

  const itinerarySchema = {
    type: Type.OBJECT,
    properties: {
      routeName: { type: Type.STRING },
      totalDistance: { type: Type.STRING },
      totalDuration: { type: Type.STRING },
      summary: { type: Type.STRING },
      stops: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.NUMBER },
            city: { type: Type.STRING },
            activity: { type: Type.STRING },
            profitabilityJustification: { type: Type.STRING },
            demandScore: { type: Type.NUMBER },
            trendVelocity: { type: Type.STRING },
            clusterInfo: {
              type: Type.OBJECT,
              properties: {
                anchorCity: { type: Type.STRING },
                clusterVolume: { type: Type.STRING },
              },
            },
            nightsToStay: { type: Type.NUMBER },
            travelTimeFromPrev: { type: Type.STRING },
            travelToNext: { type: Type.STRING },
            coordinates: {
              type: Type.OBJECT,
              properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER },
              },
            },
          },
          required: ["day", "city", "activity", "demandScore", "nightsToStay"],
        },
      },
    },
    required: ["routeName", "stops", "summary"],
  };

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        maxOutputTokens: 8192,
        thinkingConfig: { thinkingBudget: 4096 },
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const result = JSON.parse(response.text) as Itinerary;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const globalSources: GroundingSource[] = [];
    if (chunks) {
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                globalSources.push({
                    title: chunk.web.title || "Reference Source",
                    uri: chunk.web.uri
                });
            }
        });
    }
    result.sources = Array.from(new Map(globalSources.map(s => [s.uri, s])).values());

    // Precise Source Mapping
    result.stops = result.stops.map(stop => {
        const cityKeywords = stop.city.toLowerCase().split(',')[0].trim();
        const stopSources = globalSources.filter(s => 
            s.title.toLowerCase().includes(cityKeywords) || 
            s.uri.toLowerCase().includes(cityKeywords.replace(/\s/g, ''))
        );
        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    result.origin = data.origin;
    result.destination = data.destination;

    // Safety sort
    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

export const generateMarketInsights = async (): Promise<MarketInsight> => {
    const ai = getClient();
    const today = new Date().toISOString().split('T')[0];
    const prompt = `
      DATE: ${today}. 
      TASK: Generate a Market Intelligence Report for the US 'Male Massage & Wellness' sector.
      KEYWORDS: gay massage, sensual massage, male massage therapist, gay spa massage.
    `;

    const insightSchema = {
      type: Type.OBJECT,
      properties: {
        trendingKeywords: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              keyword: { type: Type.STRING },
              volume: { type: Type.NUMBER },
              growth: { type: Type.STRING },
            }
          }
        },
        topClusters: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              city: { type: Type.STRING },
              score: { type: Type.NUMBER },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          }
        },
        seasonalAdvice: { type: Type.STRING },
        lastUpdated: { type: Type.STRING },
      },
      required: ["trendingKeywords", "topClusters", "seasonalAdvice"],
    };

    try {
      const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: prompt,
        config: {
          maxOutputTokens: 8192,
          thinkingConfig: { thinkingBudget: 2048 },
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: insightSchema,
        },
      });

      const result = JSON.parse(response.text) as MarketInsight;
      return { ...result, lastUpdated: today };
    } catch (error) {
      console.error("Insights Error:", error);
      throw error;
    }
};

import React, { useState, useMemo } from 'react';
import { Itinerary, Stop } from '../types';
import { 
  Calendar, 
  Map as MapIcon, 
  Clock, 
  Navigation, 
  Utensils, 
  Camera, 
  Car, 
  Moon, 
  RefreshCw, 
  Share2, 
  ChevronDown, 
  ChevronUp,
  TrendingUp,
  AlertTriangle,
  Copy,
  ExternalLink,
  Check,
  Download
} from 'lucide-react';

interface ItineraryDisplayProps {
  itinerary: Itinerary | null;
  isLoading: boolean;
  onGenerateAlternative: () => void;
}

// -- View Models --
interface Activity {
  time: string;
  location: string;
  description: string;
  type: 'food' | 'sightseeing' | 'drive' | 'rest' | 'other';
  meta?: {
    demandScore?: number;
    justification?: string;
  };
}

interface DayPlan {
  title: string;
  activities: Activity[];
}

export const ItineraryDisplay: React.FC<ItineraryDisplayProps> = ({ 
  itinerary, 
  isLoading, 
  onGenerateAlternative 
}) => {
  const [activeTab, setActiveTab] = useState<'timeline' | 'logistics'>('timeline');
  const [copied, setCopied] = useState(false);

  // --- Transform Data to View Model ---
  const dayPlans = useMemo<DayPlan[]>(() => {
    if (!itinerary?.stops) return [];

    // Group stops by day, but handle travel segments logic
    const plans: DayPlan[] = [];
    const groupedStops = new Map<number, Stop>();

    // Sort just in case
    const sortedStops = [...itinerary.stops].sort((a, b) => a.day - b.day);

    sortedStops.forEach(stop => {
        // Find or create day plan
        let dayPlan = plans.find(p => p.title.includes(`Day ${stop.day}`));

        if (!dayPlan) {
            // New Day
            dayPlan = {
                title: `${stop.city}`,
                activities: []
            };
            plans.push(dayPlan);
        }

        // 1. Add Drive Segment if applicable
        if (stop.travelTimeFromPrev) {
             dayPlan.activities.push({
                time: "Morning", // Approximate
                location: "En Route",
                description: `Drive from previous location. Duration: ${stop.travelTimeFromPrev}`,
                type: 'drive'
             });
        }

        // 2. Add Main Activity (Market Focus)
        dayPlan.activities.push({
            time: "Afternoon", 
            location: stop.city,
            description: stop.activity,
            type: 'sightseeing',
            meta: {
                demandScore: stop.demandScore,
                justification: stop.profitabilityJustification
            }
        });

        // 3. Add Stay
        if (stop.nightsToStay > 0) {
             dayPlan.activities.push({
                time: "Evening",
                location: stop.city,
                description: `Check-in for ${stop.nightsToStay} night${stop.nightsToStay > 1 ? 's' : ''}.`,
                type: 'rest'
             });
        } else {
             dayPlan.activities.push({
                time: "Evening",
                location: stop.city,
                description: "Short stopover. Continuing journey.",
                type: 'other'
             });
        }
    });

    return plans;
  }, [itinerary]);

  const getGoogleMapsUrl = () => {
    if (!itinerary || !itinerary.stops.length) return '#';

    const origin = encodeURIComponent(itinerary.origin || '');
    const destination = encodeURIComponent(itinerary.destination || '');

    // Filter stops to avoid duplicating origin/destination if they appear in the stop list
    // and take only the first 8 stops to adhere to common URL limits (total 10 points)
    const waypoints = itinerary.stops
        .filter(s => s.city !== itinerary.origin && s.city !== itinerary.destination)
        .slice(0, 8) 
        .map(s => encodeURIComponent(s.city))
        .join('|');

    return `https://www.google.com/maps/dir/?api=1&origin=${origin}&destination=${destination}&waypoints=${waypoints}&travelmode=driving`;
  };

  const handleCopyItinerary = () => {
    if (!itinerary) return;

    const text = [
        `ROAD TRIP: ${itinerary.routeName}`,
        `Route: ${itinerary.origin} -> ${itinerary.destination}`,
        `Stats: ${itinerary.totalDistance} | ${itinerary.totalDuration}`,
        `\n--- ITINERARY ---`,
        ...itinerary.stops.map(s => 
            `Day ${s.day}: ${s.city} (Score: ${s.demandScore})\nFocus: ${s.activity}\nStay: ${s.nightsToStay} nights`
        )
    ].join('\n');

    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  const handleDownloadItinerary = () => {
    if (!itinerary) return;

    const content = [
        `ROAD TRIP PLAN: ${itinerary.routeName}`,
        `Generated on: ${new Date().toLocaleDateString()}`,
        `Route: ${itinerary.origin} to ${itinerary.destination}`,
        `Total Distance: ${itinerary.totalDistance}`,
        `Total Duration: ${itinerary.totalDuration}`,
        `Summary: ${itinerary.summary}`,
        `----------------------------------------\n`,
        ...itinerary.stops.map(stop => 
            `DAY ${stop.day}: ${stop.city.toUpperCase()}\n` +
            `• Demand Score: ${stop.demandScore}/100 (${stop.trendVelocity})\n` +
            `• Strategy: ${stop.activity}\n` +
            `• Insight: ${stop.profitabilityJustification}\n` +
            `• Stay: ${stop.nightsToStay} Nights\n` +
            `• Travel: ${stop.travelToNext ? `Next leg ${stop.travelToNext}` : 'End of leg'}\n` +
            `----------------------------------------\n`
        ),
        `\nExported from RoadTripPro`
    ].join('\n');

    const blob = new Blob([content], { type: 'text/plain' });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `RoadTrip-${itinerary.origin.split(',')[0]}-to-${itinerary.destination.split(',')[0]}.txt`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  // 1. Loading State (Skeleton UI)
  if (isLoading) {
    return (
      <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-sm border border-gray-100 overflow-hidden">
        {/* Skeleton Header */}
        <div className="p-6 border-b border-gray-100 space-y-4">
          <div className="h-8 bg-gray-100 rounded-md w-3/4 animate-pulse" />
          <div className="flex gap-3">
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
            <div className="h-4 bg-gray-100 rounded w-20 animate-pulse" />
          </div>
        </div>
        {/* Skeleton Content */}
        <div className="flex-1 p-6 space-y-8 overflow-y-auto custom-scrollbar">
          {[1, 2, 3].map((i) => (
            <div key={i} className="flex gap-4">
              <div className="flex flex-col items-center gap-2">
                <div className="w-8 h-8 rounded-full bg-gray-100 animate-pulse" />
                <div className="w-0.5 h-24 bg-gray-50" />
              </div>
              <div className="flex-1 space-y-3">
                <div className="h-6 bg-gray-100 rounded w-1/3 animate-pulse" />
                <div className="h-24 bg-gray-50 rounded-xl w-full animate-pulse" />
              </div>
            </div>
          ))}
        </div>
      </div>
    );
  }

  // 2. Empty State
  if (!itinerary) {
    return (
      <div className="h-full flex flex-col items-center justify-center bg-white/50 lg:bg-white lg:rounded-2xl lg:border border-gray-100 text-center p-8">
        <div className="w-24 h-24 bg-rose-50 rounded-full flex items-center justify-center mb-6 shadow-sm">
          <MapIcon className="w-10 h-10 text-[#FF385C]" />
        </div>
        <h2 className="text-2xl font-bold text-gray-900 mb-2">Ready to hit the road?</h2>
        <p className="text-gray-500 max-w-md leading-relaxed">
          Enter your trip details on the left to generate a perfectly curated day-by-day itinerary tailored to your preferences.
        </p>
      </div>
    );
  }

  // 3. Render Result
  return (
    <div className="h-full flex flex-col bg-white lg:rounded-2xl shadow-xl border border-gray-100 overflow-hidden">

      {/* Header Section */}
      <div className="flex-none p-6 border-b border-gray-100 bg-white z-10">
        <div className="flex flex-col xl:flex-row xl:items-start xl:justify-between gap-4">
          <div>
            <h2 className="text-2xl font-bold text-gray-900 leading-tight">
              {itinerary.routeName || "Your Road Trip Adventure"}
            </h2>
            <p className="text-gray-500 mt-1 flex items-center gap-2 text-sm">
              <Calendar className="w-4 h-4" />
              {itinerary.summary || "Custom curated itinerary"}
            </p>
          </div>

          <div className="flex flex-wrap items-center gap-2">
            <button 
              onClick={onGenerateAlternative}
              className="px-4 py-2 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 rounded-full text-sm font-medium transition-colors flex items-center gap-2 shadow-sm"
            >
              <RefreshCw className="w-4 h-4" />
              <span className="hidden sm:inline">Alternative</span>
            </button>

            <button 
                onClick={handleCopyItinerary}
                className="px-4 py-2 bg-white border border-gray-200 hover:bg-gray-50 text-gray-700 rounded-full text-sm font-medium transition-colors flex items-center gap-2 shadow-sm"
            >
              {copied ? <Check className="w-4 h-4 text-green-500" /> : <Copy className="w-4 h-4" />}
              <span className="hidden sm:inline">{copied ? "Copied" : "Copy"}</span>
            </button>

            <button 
                onClick={handleDownloadItinerary}
                className="px-4 py-2 bg-gray-900 hover:bg-black text-white rounded-full text-sm font-medium transition-colors flex items-center gap-2 shadow-sm"
            >
              <Download className="w-4 h-4" />
              <span className="hidden sm:inline">Export</span>
            </button>
          </div>
        </div>

        {/* View Tabs */}
        <div className="flex gap-6 mt-6 border-b border-gray-100 -mb-6">
          <button 
            onClick={() => setActiveTab('timeline')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'timeline' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Timeline
          </button>
          <button 
            onClick={() => setActiveTab('logistics')}
            className={`pb-3 text-sm font-semibold border-b-2 transition-colors ${activeTab === 'logistics' ? 'border-[#FF385C] text-[#FF385C]' : 'border-transparent text-gray-500 hover:text-gray-700'}`}
          >
            Logistics & Map
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto bg-gray-50/50 p-4 lg:p-6 scroll-smooth custom-scrollbar">

        {activeTab === 'logistics' ? (
          <div className="max-w-3xl mx-auto space-y-6">
             {/* Navigation Card */}
             <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
                <div className="flex items-start justify-between">
                    <div>
                        <h3 className="text-lg font-bold text-gray-900 flex items-center gap-2">
                            <Navigation className="w-5 h-5 text-[#FF385C]" />
                            Route Navigation
                        </h3>
                        <p className="text-sm text-gray-500 mt-1">Get live turn-by-turn directions via Google Maps.</p>
                    </div>
                    <a 
                        href={getGoogleMapsUrl()} 
                        target="_blank" 
                        rel="noopener noreferrer"
                        className="px-5 py-2.5 bg-[#FF385C] text-white rounded-lg font-bold shadow-md hover:bg-[#d9304e] transition-all flex items-center gap-2"
                    >
                        Open Full Route
                        <ExternalLink className="w-4 h-4" />
                    </a>
                </div>

                <div className="mt-6 grid grid-cols-2 md:grid-cols-4 gap-4">
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <span className="text-xs font-bold text-gray-400 uppercase">Total Dist</span>
                        <p className="text-xl font-black text-gray-900 mt-1">{itinerary.totalDistance}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <span className="text-xs font-bold text-gray-400 uppercase">Est. Time</span>
                        <p className="text-xl font-black text-gray-900 mt-1">{itinerary.totalDuration}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <span className="text-xs font-bold text-gray-400 uppercase">Total Stops</span>
                        <p className="text-xl font-black text-gray-900 mt-1">{itinerary.stops.length}</p>
                    </div>
                    <div className="bg-gray-50 p-4 rounded-lg">
                        <span className="text-xs font-bold text-gray-400 uppercase">Route Type</span>
                        <p className="text-xl font-black text-gray-900 mt-1 capitalize">{itinerary.travelMode || "Car"}</p>
                    </div>
                </div>
             </div>

             {/* Stops Summary */}
             <div className="bg-white rounded-xl border border-gray-200 shadow-sm overflow-hidden">
                <div className="p-4 border-b border-gray-100 bg-gray-50/50">
                    <h4 className="font-bold text-gray-800">Waypoints Sequence</h4>
                </div>
                <div className="divide-y divide-gray-100">
                    <div className="p-4 flex items-center gap-3 bg-gray-50">
                        <div className="w-2 h-2 rounded-full bg-green-500"></div>
                        <span className="font-bold text-gray-900">Start: {itinerary.origin}</span>
                    </div>
                    {itinerary.stops.map((stop, i) => (
                        <div key={i} className="p-4 flex items-center gap-3 pl-8 relative group">
                             <div className="absolute left-5 top-0 bottom-0 w-0.5 bg-gray-200"></div>
                             <span className="w-6 h-6 rounded-full bg-white border border-gray-200 text-xs font-bold flex items-center justify-center z-10">
                                {i + 1}
                             </span>
                             <div className="flex-1 flex justify-between items-center">
                                <div>
                                    <p className="font-semibold text-gray-900">{stop.city}</p>
                                    <p className="text-xs text-gray-500">Day {stop.day} • {stop.nightsToStay} Night Stay</p>
                                </div>
                                <a 
                                  href={`https://www.google.com/maps/search/?api=1&query=${encodeURIComponent(stop.city)}`} 
                                  target="_blank" 
                                  rel="noopener noreferrer"
                                  className="text-gray-300 hover:text-[#FF385C] transition-colors"
                                  title="View on Map"
                                >
                                    <MapIcon className="w-4 h-4" />
                                </a>
                             </div>
                        </div>
                    ))}
                    <div className="p-4 flex items-center gap-3 bg-gray-50">
                        <div className="w-2 h-2 rounded-full bg-red-500"></div>
                        <span className="font-bold text-gray-900">End: {itinerary.destination}</span>
                    </div>
                </div>
             </div>
          </div>
        ) : (
          <div className="max-w-3xl mx-auto space-y-8 pb-12">
            {dayPlans.map((day, index) => (
              <DayCard key={index} day={day} index={index} />
            ))}
          </div>
        )}
      </div>
    </div>
  );
};

// --- Sub-Components ---

const DayCard: React.FC<{ day: DayPlan; index: number }> = ({ day, index }) => {
  const [isExpanded, setIsExpanded] = useState(true);

  return (
    <div className="bg-white rounded-xl shadow-sm border border-gray-100 overflow-hidden transition-all hover:shadow-md">
      {/* Day Header */}
      <div 
        onClick={() => setIsExpanded(!isExpanded)}
        className="p-4 flex items-center justify-between cursor-pointer bg-gray-50/50 hover:bg-gray-50 transition-colors"
      >
        <div className="flex items-center gap-4">
          <div className="w-12 h-12 rounded-lg bg-[#FF385C]/10 flex items-center justify-center text-[#FF385C] font-bold text-lg">
            {index + 1}
          </div>
          <div>
            <h3 className="font-bold text-gray-900">Day {index + 1}</h3>
            <p className="text-sm text-gray-500 font-medium">{day.title}</p>
          </div>
        </div>
        {isExpanded ? <ChevronUp className="w-5 h-5 text-gray-400" /> : <ChevronDown className="w-5 h-5 text-gray-400" />}
      </div>

      {/* Activities Timeline */}
      {isExpanded && (
        <div className="p-4 pl-6 lg:pl-10 relative">
          {/* Vertical Line */}
          <div className="absolute left-9 lg:left-[52px] top-6 bottom-6 w-0.5 bg-gray-100" />

          <div className="space-y-6 relative">
            {day.activities.map((activity, actIndex) => (
              <ActivityItem key={actIndex} activity={activity} />
            ))}
          </div>
        </div>
      )}
    </div>
  );
};

const ActivityItem: React.FC<{ activity: Activity }> = ({ activity }) => {
  const getIcon = (type?: string) => {
    switch (type?.toLowerCase()) {
      case 'food': return <Utensils className="w-4 h-4" />;
      case 'sightseeing': return <Camera className="w-4 h-4" />;
      case 'drive': return <Car className="w-4 h-4" />;
      case 'rest': return <Moon className="w-4 h-4" />;
      default: return <Navigation className="w-4 h-4" />;
    }
  };

  const getColor = (type?: string) => {
    switch (type?.toLowerCase()) {
      case 'food': return 'bg-orange-100 text-orange-600';
      case 'sightseeing': return 'bg-blue-100 text-blue-600';
      case 'drive': return 'bg-gray-100 text-gray-600';
      default: return 'bg-rose-100 text-rose-600';
    }
  };

  return (
    <div className="flex gap-4 relative group">
      {/* Timeline Dot */}
      <div className={`w-8 h-8 rounded-full flex-none flex items-center justify-center z-10 ring-4 ring-white ${getColor(activity.type)}`}>
        {getIcon(activity.type)}
      </div>

      {/* Content */}
      <div className="flex-1 pt-1">
        <div className="flex flex-col sm:flex-row sm:items-baseline gap-1 sm:gap-3 mb-1">
          <span className="text-xs font-bold text-gray-400 tracking-wide uppercase flex items-center gap-1">
            <Clock className="w-3 h-3" />
            {activity.time}
          </span>
          <h4 className="font-semibold text-gray-900 text-sm">
            {activity.location || "En Route"}
          </h4>
        </div>
        <p className="text-gray-600 text-sm leading-relaxed">
          {activity.description}
        </p>

        {/* Market Data Injection */}
        {activity.meta?.demandScore !== undefined && (
            <div className="mt-3 bg-blue-50/50 border border-blue-100 rounded-lg p-3">
                <div className="flex items-center gap-2 mb-1">
                    <TrendingUp className="w-3 h-3 text-blue-500" />
                    <span className="text-xs font-bold text-blue-700">Market Intelligence</span>
                </div>
                <div className="flex justify-between items-start">
                    <p className="text-xs text-blue-600/80 leading-snug flex-1 pr-4">{activity.meta.justification}</p>
                    <div className="bg-white px-2 py-1 rounded border border-blue-100 shadow-sm text-center">
                        <span className="block text-xs font-black text-gray-900">{activity.meta.demandScore}</span>
                        <span className="block text-[8px] uppercase font-bold text-gray-400">Score</span>
                    </div>
                </div>
            </div>
        )}
      </div>
    </div>
  );
};

