import { GoogleGenAI, Type } from "@google/genai";
import { TripFormData, Itinerary, TravelMode, MarketInsight, GroundingSource, Stop } from "../types";
import { GEMINI_MODEL } from "../constants";

const getClient = () => {
  const apiKey = process.env.API_KEY;
  if (!apiKey) {
    throw new Error("API Key is missing");
  }
  return new GoogleGenAI({ apiKey });
};

// Integrated from real-keywords-collector/keywords.txt
const KEYWORD_MARKET_DATA = `
TARGET NICHE KEYWORDS (Use these for Search Validation):
- gay massage, sensual massage, erotic massage
- male massage therapist, male massage near me, gay massage therapist
- male body massage, massage male to male, male massage therapy
- gay friendly massage, gay spa massage, LGBTQ massage therapist
- massage for gay men, man on man massage, LGBTQ friendly massage
- gay deep tissue massage, gay couples massage, gay sports massage
- male to male massage therapy, gay Swedish massage
- professional male massage, male aromatherapy massage
- gay Thai massage, certified male massage therapist
`;

export const generateItinerary = async (data: TripFormData, isAlternative: boolean = false): Promise<Itinerary> => {
  const ai = getClient();
  const today = new Date().toLocaleDateString('en-US', { year: 'numeric', month: 'long', day: 'numeric' });

  const mandatoryStopsText = data.mandatoryStops.length > 0
    ? data.mandatoryStops.map(s => `${s.location}${s.arrivalDate ? ` (Arrive: ${s.arrivalDate})` : ''}`).join(', ')
    : 'None';

  const originText = data.origin ? data.origin : "Flexible/User-Decided (Suggest a logical start based on stops/market)";
  const destinationText = data.destination ? data.destination : "Flexible/User-Decided (Suggest a logical end)";
  const driveConstraint = data.maxDriveHours > 0 ? `${data.maxDriveHours} hours per leg` : "Auto-optimized for best experience";

  const prompt = `
    TODAY'S DATE: ${today}
    ROLE: You are a specialized Logistics & Market Analyst for the male wellness sector.

    GOAL: Create a high-revenue road trip itinerary starting from ${originText} and ending at ${destinationText}${data.destinationDate ? ` (Arrival by: ${data.destinationDate})` : ''}.

    CONSTRAINTS:
    - Max Drive: ${driveConstraint}.
    - Mandatory Stops: ${mandatoryStopsText}.
    - Total Stops: Approx ${data.numberOfStops}.
    - Strategy: ${isAlternative ? 'Explore high-growth secondary markets (blue ocean strategy).' : 'Stick to established high-volume hubs (red ocean strategy).'}

    ${KEYWORD_MARKET_DATA}

    STRICT RULES FOR 'nightsToStay' (Classificação Final Definitiva):
    - **Score 90-100 (Platinum)**: 3 Nights.
    - **Score 75-89 (Gold)**: 2 Nights.
    - **Score 60-74 (Silver)**: 1 Night.
    - **Score < 60 (Bronze)**: 0 Nights (Day stop / Lunch only).
    - **Safety Override**: If search indicates active safety risks for LGBTQ+ travelers in the area, force 'nightsToStay' = 0.

    EXECUTION STEPS:
    1. **Route Logic**: Plan a feasible driving route. If Origin/Destination are "Flexible", suggest major hubs near the Mandatory Stops.
    2. **Market Validation**: Use Google Search to check demand in intermediate cities.
    3. **Evidence-Based Justification**: Cite specific events/venues.
  `;

  const itinerarySchema = {
    type: Type.OBJECT,
    properties: {
      routeName: { type: Type.STRING },
      totalDistance: { type: Type.STRING },
      totalDuration: { type: Type.STRING },
      summary: { type: Type.STRING },
      stops: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            day: { type: Type.NUMBER },
            city: { type: Type.STRING },
            activity: { type: Type.STRING },
            profitabilityJustification: { type: Type.STRING },
            demandScore: { type: Type.NUMBER },
            trendVelocity: { type: Type.STRING },
            clusterInfo: {
              type: Type.OBJECT,
              properties: {
                anchorCity: { type: Type.STRING },
                clusterVolume: { type: Type.STRING },
              },
            },
            nightsToStay: { type: Type.NUMBER },
            travelTimeFromPrev: { type: Type.STRING },
            travelToNext: { type: Type.STRING },
            coordinates: {
              type: Type.OBJECT,
              properties: {
                lat: { type: Type.NUMBER },
                lng: { type: Type.NUMBER },
              },
            },
          },
          required: ["day", "city", "activity", "demandScore", "nightsToStay"],
        },
      },
    },
    required: ["routeName", "stops", "summary"],
  };

  try {
    const response = await ai.models.generateContent({
      model: GEMINI_MODEL,
      contents: prompt,
      config: {
        maxOutputTokens: 8192,
        thinkingConfig: { thinkingBudget: 4096 },
        tools: [{ googleSearch: {} }],
        responseMimeType: "application/json",
        responseSchema: itinerarySchema,
      },
    });

    const text = response.text;
    if (!text) {
        throw new Error("No content generated");
    }

    // Clean any potential markdown wrapping (```json ... ```) which can sometimes occur
    const cleanText = text.replace(/^```json\s*/, '').replace(/\s*```$/, '');
    const result = JSON.parse(cleanText) as Itinerary;

    const chunks = response.candidates?.[0]?.groundingMetadata?.groundingChunks;
    const globalSources: GroundingSource[] = [];
    if (chunks) {
        chunks.forEach((chunk: any) => {
            if (chunk.web) {
                globalSources.push({
                    title: chunk.web.title || "Reference Source",
                    uri: chunk.web.uri
                });
            }
        });
    }
    result.sources = Array.from(new Map(globalSources.map(s => [s.uri, s])).values());

    // Precise Source Mapping
    result.stops = result.stops.map(stop => {
        const cityKeywords = stop.city.toLowerCase().split(',')[0].trim();
        const stopSources = globalSources.filter(s => 
            s.title.toLowerCase().includes(cityKeywords) || 
            s.uri.toLowerCase().includes(cityKeywords.replace(/\s/g, ''))
        );
        return {
            ...stop,
            stopSources: stopSources.length > 0 ? Array.from(new Map(stopSources.map(s => [s.uri, s])).values()) : undefined
        };
    });

    result.startDate = data.startDate;
    // If the API generated a route with a specific start/end that wasn't provided, use that. 
    // Otherwise fallback to form data (or "Flexible" if that was empty).
    // However, the itinerary usually doesn't return explicit 'origin'/'destination' fields in the root schema 
    // based on our prompt schema, so we derive it or keep it as is.
    result.origin = data.origin || result.stops[0]?.city || "Unknown Start";
    result.destination = data.destination || result.stops[result.stops.length - 1]?.city || "Unknown End";

    // Safety sort
    result.stops.sort((a, b) => a.day - b.day);

    return result;
  } catch (error: any) {
    console.error("Gemini Error:", error);
    throw new Error(error.message || "Route calculation failed. Check your API key and network.");
  }
};

export const generateMarketInsights = async (): Promise<MarketInsight> => {
    const ai = getClient();
    const today = new Date().toISOString().split('T')[0];
    const prompt = `
      DATE: ${today}. 
      TASK: Generate a Market Intelligence Report for the US 'Male Massage & Wellness' sector.
      KEYWORDS: gay massage, sensual massage, male massage therapist, gay spa massage.
    `;

    const insightSchema = {
      type: Type.OBJECT,
      properties: {
        trendingKeywords: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              keyword: { type: Type.STRING },
              volume: { type: Type.NUMBER },
              growth: { type: Type.STRING },
            }
          }
        },
        topClusters: {
          type: Type.ARRAY,
          items: {
            type: Type.OBJECT,
            properties: {
              city: { type: Type.STRING },
              score: { type: Type.NUMBER },
              tags: {
                type: Type.ARRAY,
                items: { type: Type.STRING }
              }
            }
          }
        },
        seasonalAdvice: { type: Type.STRING },
        lastUpdated: { type: Type.STRING },
      },
      required: ["trendingKeywords", "topClusters", "seasonalAdvice"],
    };

    try {
      const response = await ai.models.generateContent({
        model: GEMINI_MODEL,
        contents: prompt,
        config: {
          maxOutputTokens: 8192,
          thinkingConfig: { thinkingBudget: 2048 },
          tools: [{ googleSearch: {} }],
          responseMimeType: "application/json",
          responseSchema: insightSchema,
        },
      });

      const text = response.text;
      if (!text) {
          throw new Error("No insights generated");
      }
      const cleanText = text.replace(/^```json\s*/, '').replace(/\s*```$/, '');
      const result = JSON.parse(cleanText) as MarketInsight;

      return { ...result, lastUpdated: today };
    } catch (error) {
      console.error("Insights Error:", error);
      throw error;
    }
};

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Minus, Info, Edit2, Check, ChevronDown, ChevronUp, AlertCircle, Sparkles, Trash2, Save, Moon, Locate, LocateFixed } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

const EMPTY_STOP: MandatoryStop = { location: '', date: '', arrivalDate: '', nights: 1 };

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  // Modal State
  const [isStopModalOpen, setIsStopModalOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState<number | null>(null); // null means adding new
  const [tempStop, setTempStop] = useState<MandatoryStop>(EMPTY_STOP);
  const [isLocating, setIsLocating] = useState(false);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // --- Geolocation Logic ---
  const performGeolocation = useCallback((isAuto: boolean) => {
    if (!navigator.geolocation) {
      if (!isAuto) alert("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        // Format to 4 decimal places for cleanliness
        const locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;

        // Use setFormData directly to ensure state update
        setFormData(prev => ({ ...prev, origin: locString }));
        setIsLocating(false);
      },
      (error) => {
        console.error("Geolocation error:", error);
        if (!isAuto) {
            alert("Unable to retrieve your location. Please check permissions.");
        }
        setIsLocating(false);
      }
    );
  }, []);

  // Automatic Geolocation on Load
  useEffect(() => {
    // Only attempt to auto-locate if the origin is empty
    if (!formData.origin) {
        performGeolocation(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run only once on mount

  const handleGeolocationClick = () => {
    performGeolocation(false);
  };

  // --- Modal Logic ---

  const openAddStopModal = () => {
    setTempStop({ ...EMPTY_STOP });
    setEditingIndex(null);
    setIsStopModalOpen(true);
  };

  const openEditStopModal = (index: number) => {
    setTempStop({ ...formData.mandatoryStops[index] });
    setEditingIndex(index);
    setIsStopModalOpen(true);
  };

  const handleTempStopChange = (field: keyof MandatoryStop, value: string | number) => {
    setTempStop(prev => ({ ...prev, [field]: value }));
  };

  const saveStop = () => {
    const newStops = [...formData.mandatoryStops];
    if (editingIndex !== null) {
      // Update existing
      newStops[editingIndex] = tempStop;
    } else {
      // Add new
      newStops.push(tempStop);
    }
    handleChange('mandatoryStops', newStops);
    setIsStopModalOpen(false);
  };

  const removeStop = (index: number) => {
    const newStops = formData.mandatoryStops.filter((_, i) => i !== index);
    handleChange('mandatoryStops', newStops);
  };

  const deleteCurrentStop = () => {
    if (editingIndex !== null) {
      removeStop(editingIndex);
    }
    setIsStopModalOpen(false);
  };

  // --- Helper Renderers ---

  const getModeIcon = (mode: string) => {
    switch (mode) {
      case TravelMode.Car: return <Car className="w-5 h-5" />;
      case TravelMode.Bus: return <Bus className="w-5 h-5" />;
      case TravelMode.Plane: return <Plane className="w-5 h-5" />;
      default: return <Shuffle className="w-5 h-5" />;
    }
  };

  const renderError = (fieldName: string) => {
      if (!validationErrors || !validationErrors[fieldName]) return null;
      const err = validationErrors[fieldName];
      return (
          <div className="mt-2 flex items-start gap-2 animate-in slide-in-from-top-1 fade-in duration-300">
             <div className="min-w-[4px] h-full bg-red-400 rounded-full mt-1"></div>
             <div>
                <p className="text-xs font-bold text-red-600 leading-tight">{err.message}</p>
                <p className="text-[10px] text-red-400 font-medium mt-0.5 flex items-center gap-1">
                  <Sparkles className="w-3 h-3" />
                  {err.suggestion}
                </p>
             </div>
          </div>
      );
  };

  const getInputClass = (fieldName: string, baseClass: string) => {
      const hasError = validationErrors && validationErrors[fieldName];
      return `${baseClass} ${hasError ? 'bg-red-50/50 text-red-900 placeholder-red-300' : 'bg-transparent text-gray-900 placeholder-gray-400'}`;
  };

  const getContainerClass = (fieldName: string, baseClass: string) => {
       const hasError = validationErrors && validationErrors[fieldName];
       return `${baseClass} ${hasError ? 'bg-red-50 border-red-200' : ''}`;
  };

  return (
    <div className="h-full flex flex-col bg-white relative">
      <div className="p-6 pb-2 border-b border-gray-100 lg:border-none">
        <h2 className="text-2xl font-bold text-gray-800">Where to?</h2>
        <p className="text-gray-500 text-sm mt-1">Configure your professional road trip</p>
      </div>

      <div className="flex-1 overflow-y-auto p-6 space-y-6 custom-scrollbar">
        {/* Origin & Destination Card */}
        <div className={`bg-white border rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden transition-colors border-gray-200`}>
          {/* Origin */}
          <div className={getContainerClass('origin', 'relative p-4 border-b border-gray-100 hover:bg-gray-50 transition-colors')}>
            <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.origin ? 'text-red-500' : 'text-gray-500'}`}>Origin</label>
            <div className="flex items-center gap-2">
                <input
                type="text"
                value={formData.origin}
                onChange={(e) => handleChange('origin', e.target.value)}
                className={getInputClass('origin', "w-full font-semibold text-lg focus:outline-none")}
                placeholder="Starting Point (Optional)"
                />
                <button 
                  onClick={handleGeolocationClick}
                  disabled={isLocating}
                  className={`p-2 rounded-full transition-colors ${isLocating ? 'bg-blue-50 text-blue-400' : 'hover:bg-gray-100 text-gray-400 hover:text-[#FF385C]'}`}
                  title="Use Current Location"
                >
                    {isLocating ? <LocateFixed className="w-5 h-5 animate-pulse" /> : <Locate className="w-5 h-5" />}
                </button>
            </div>

            {renderError('origin')}
          </div>

          {/* Destination */}
          <div className={getContainerClass('destination', 'relative p-4 hover:bg-gray-50 transition-colors')}>
            <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.destination ? 'text-red-500' : 'text-gray-500'}`}>Destination</label>
            <input
              type="text"
              value={formData.destination}
              onChange={(e) => handleChange('destination', e.target.value)}
              className={getInputClass('destination', "w-full font-semibold text-lg focus:outline-none")}
              placeholder="Final Destination (Optional)"
            />
             <div className="absolute right-4 top-1/2 -translate-y-1/2 flex items-center gap-2">
                 {validationErrors?.destination ? <AlertCircle className="w-5 h-5 text-red-500" /> : <MapPin className="w-5 h-5 text-gray-400" />}
            </div>
             {renderError('destination')}
          </div>
           {/* Destination Date */}
           <div className="relative p-4 border-t border-gray-100 hover:bg-gray-50 transition-colors bg-gray-50/50">
            <label className="text-[10px] font-bold uppercase tracking-wider text-gray-500 block mb-1">Target Arrival Date (Optional)</label>
            <input
              type="date"
              value={formData.destinationDate}
              onChange={(e) => handleChange('destinationDate', e.target.value)}
              className="w-full bg-transparent text-gray-700 font-medium focus:outline-none text-base appearance-none min-h-[44px]"
            />
          </div>
        </div>

        {/* Dates Card */}
        <div className={`bg-white border rounded-2xl shadow-[0_6px_16px_rgba(0,0,0,0.08)] overflow-hidden flex flex-col transition-colors border-gray-200`}>
           <div className="flex sm:flex-row flex-col">
              <div className={getContainerClass('startDate', 'flex-1 p-4 border-b sm:border-b-0 sm:border-r border-gray-100 hover:bg-gray-50 transition-colors')}>
                <div className="flex justify-between">
                    <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.startDate ? 'text-red-500' : 'text-gray-500'}`}>Start Date</label>
                    {validationErrors?.startDate && <AlertCircle className="w-3 h-3 text-red-500" />}
                </div>
                <input
                  type="date"
                  value={formData.startDate}
                  onChange={(e) => handleChange('startDate', e.target.value)}
                  className={getInputClass('startDate', "w-full font-medium focus:outline-none text-base appearance-none min-h-[44px]")}
                />
              </div>
              <div className={getContainerClass('endDate', 'flex-1 p-4 hover:bg-gray-50 transition-colors')}>
                <div className="flex justify-between">
                    <label className={`text-[10px] font-bold uppercase tracking-wider block mb-1 ${validationErrors?.endDate ? 'text-red-500' : 'text-gray-500'}`}>Return Date</label>
                    {validationErrors?.endDate && <AlertCircle className="w-3 h-3 text-red-500" />}
                </div>
                <input
                  type="date"
                  value={formData.endDate}
                  onChange={(e) => handleChange('endDate', e.target.value)}
                  className={getInputClass('endDate', "w-full font-medium focus:outline-none text-base appearance-none min-h-[44px]")}
                />
              </div>
           </div>
           {(validationErrors?.startDate || validationErrors?.endDate) && (
              <div className="px-4 pb-3 pt-0">
                  {renderError('startDate')}
                  {renderError('endDate')}
              </div>
            )}
        </div>

        {/* Mandatory Stops (Improved UI) */}
        <div>
          <div className="flex items-center justify-between mb-3">
             <label className="text-sm font-bold text-gray-800">Must-visit Cities</label>
          </div>

          <div className="space-y-3">
            {formData.mandatoryStops.map((stop, index) => (
              <div 
                key={index} 
                onClick={() => openEditStopModal(index)}
                className="bg-white border border-gray-200 hover:border-[#FF385C] rounded-xl p-3 flex items-center justify-between group cursor-pointer transition-all shadow-sm hover:shadow-md"
              >
                  <div className="flex items-center gap-3">
                    <div className="w-8 h-8 rounded-full bg-gray-100 flex items-center justify-center text-gray-500 group-hover:bg-[#FF385C] group-hover:text-white transition-colors">
                      <MapPin className="w-4 h-4" />
                    </div>
                    <div>
                      <h4 className="text-sm font-bold text-gray-900 leading-tight">{stop.location || 'Untitled Stop'}</h4>
                      <div className="flex items-center gap-2 mt-0.5">
                          <span className="text-[10px] text-gray-500 font-medium bg-gray-50 px-1.5 py-0.5 rounded border border-gray-100">
                             {stop.arrivalDate || stop.date || 'Flexible'}
                          </span>
                          <span className="text-[10px] text-gray-500 font-medium">
                            {stop.nights} Night{stop.nights !== 1 ? 's' : ''}
                          </span>
                      </div>
                    </div>
                  </div>
                  <div className="text-gray-300 group-hover:text-[#FF385C]">
                     <Edit2 className="w-4 h-4" />
                  </div>
              </div>
            ))}

            <button
              onClick={openAddStopModal}
              className="w-full py-3 rounded-xl border-2 border-dashed border-gray-200 text-gray-400 font-bold text-sm hover:border-[#FF385C] hover:text-[#FF385C] hover:bg-[#FF385C]/5 transition-all flex items-center justify-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Add Mandatory Stop
            </button>
          </div>
        </div>

        {/* Preferences */}
        <div>
           <label className="text-sm font-bold text-gray-800 mb-3 block">Travel Preferences</label>
           <div className="bg-white border border-gray-200 rounded-2xl p-4 shadow-sm space-y-5">

              {/* Travel Mode */}
              <div>
                <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Mode of Transport</span>
                <div className="grid grid-cols-4 gap-2 mb-3">
                  {Object.values(TravelMode).map((mode) => (
                    <button
                      key={mode}
                      onClick={() => handleChange('travelMode', mode)}
                      className={`flex flex-col items-center justify-center p-2 rounded-xl border transition-all ${
                        formData.travelMode === mode
                          ? 'bg-gray-900 border-gray-900 text-white'
                          : 'bg-white border-gray-200 text-gray-600 hover:border-gray-300'
                      }`}
                    >
                      {getModeIcon(mode)}
                      <span className="text-[10px] font-bold mt-1">{mode}</span>
                    </button>
                  ))}
                </div>
                {formData.travelMode === TravelMode.Mixed && (
                  <div className="bg-gray-50 p-3 rounded-lg border border-gray-200">
                      <div className="flex items-center gap-2 mb-1">
                        <Info className="w-3 h-3 text-gray-500" />
                        <span className="text-[10px] font-bold uppercase text-gray-500">Mixed Mode Details</span>
                      </div>
                      <input 
                        type="text"
                        value={formData.travelModeDetail || ''}
                        onChange={(e) => handleChange('travelModeDetail', e.target.value)}
                        placeholder="e.g. Fly to Denver, then rent car"
                        className="w-full bg-white border border-gray-200 rounded px-2 py-1.5 text-xs text-gray-800 focus:outline-none focus:border-gray-400"
                      />
                  </div>
                )}
              </div>

              <div className="grid grid-cols-2 gap-4">
                  <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block flex items-center gap-1">
                        Max Drive Hours <Clock className="w-3 h-3" />
                      </span>
                      <div className="relative">
                          <select
                            value={formData.maxDriveHours}
                            onChange={(e) => handleChange('maxDriveHours', parseInt(e.target.value))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-sm font-bold text-gray-900 focus:outline-none focus:border-gray-400 appearance-none"
                          >
                            <option value={0}>Auto (Recommended)</option>
                            <option value={4}>4 Hours</option>
                            <option value={6}>6 Hours</option>
                            <option value={8}>8 Hours</option>
                            <option value={10}>10 Hours</option>
                            <option value={12}>12 Hours</option>
                          </select>
                          <ChevronDown className="w-4 h-4 text-gray-500 absolute right-3 top-1/2 -translate-y-1/2 pointer-events-none" />
                      </div>
                  </div>
                   <div>
                      <span className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-2 block">Target Stops</span>
                       <div className="relative">
                            <input
                            type="number"
                            min={1}
                            max={20}
                            value={formData.numberOfStops}
                            onChange={(e) => handleChange('numberOfStops', parseInt(e.target.value))}
                            className="w-full bg-gray-50 border border-gray-200 rounded-lg py-2 px-3 text-sm font-bold text-gray-900 focus:outline-none focus:border-gray-400"
                            placeholder="Auto"
                          />
                       </div>
                  </div>
              </div>

           </div>
        </div>

      </div>

      <div className="p-6 border-t border-gray-100 bg-white">
        <button
          onClick={() => onSubmit(formData, false)}
          disabled={isLoading}
          className={`w-full py-4 rounded-xl font-bold text-white text-lg shadow-[0_6px_20px_rgba(255,56,92,0.4)] transition-all transform hover:scale-[1.01] active:scale-[0.98] flex items-center justify-center gap-2 ${
            isLoading 
              ? 'bg-gray-300 cursor-not-allowed shadow-none' 
              : 'bg-gradient-to-r from-[#FF385C] to-[#BD1E59]'
          }`}
        >
          {isLoading ? (
             'Generating...' 
          ) : (
            <>
                <Search className="w-5 h-5" />
                Explore Plan
            </>
          )}
        </button>

        <button
          onClick={() => onSubmit(formData, true)}
          disabled={isLoading}
          className="w-full mt-3 py-3 rounded-xl font-bold text-gray-600 bg-transparent border border-gray-200 hover:bg-gray-50 transition-all text-sm"
        >
           Generate Alternative Route
        </button>
      </div>

      {/* --- Stop Editor Modal --- */}
      {isStopModalOpen && (
        <div className="absolute inset-0 z-50 flex items-center justify-center bg-gray-900/40 backdrop-blur-[2px] p-4 animate-in fade-in duration-200">
           <div className="bg-white w-full max-w-sm rounded-3xl shadow-2xl p-6 animate-in zoom-in-95 duration-200 border border-gray-100">
              <div className="flex items-center justify-between mb-6">
                 <h3 className="text-lg font-black text-gray-800">
                   {editingIndex !== null ? 'Edit Stop' : 'Add Stop'}
                 </h3>
                 <button onClick={() => setIsStopModalOpen(false)} className="p-2 bg-gray-50 rounded-full hover:bg-gray-100 transition-colors">
                    <X className="w-5 h-5 text-gray-500" />
                 </button>
              </div>

              <div className="space-y-4">
                 <div>
                    <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">City Location</label>
                    <div className="relative">
                       <MapPin className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                       <input 
                         type="text" 
                         value={tempStop.location}
                         onChange={(e) => handleTempStopChange('location', e.target.value)}
                         className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all placeholder-gray-400"
                         placeholder="e.g. Austin, TX"
                         autoFocus
                       />
                    </div>
                 </div>

                 <div className="grid grid-cols-2 gap-4">
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Arrival</label>
                      <div className="relative">
                         <Calendar className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="date" 
                           value={tempStop.arrivalDate || tempStop.date || ''}
                           onChange={(e) => handleTempStopChange('arrivalDate', e.target.value)}
                           className="w-full pl-9 pr-2 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 text-xs focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all appearance-none"
                         />
                      </div>
                    </div>
                    <div>
                      <label className="text-[10px] font-bold text-gray-400 uppercase block mb-1.5 ml-1">Duration</label>
                      <div className="relative">
                         <Moon className="absolute left-3 top-1/2 -translate-y-1/2 w-4 h-4 text-gray-400" />
                         <input 
                           type="number"
                           min={1}
                           max={14}
                           value={tempStop.nights}
                           onChange={(e) => handleTempStopChange('nights', parseInt(e.target.value) || 1)}
                           className="w-full pl-9 pr-4 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all"
                         />
                         <span className="absolute right-3 top-1/2 -translate-y-1/2 text-xs font-bold text-gray-400 pointer-events-none">Nights</span>
                      </div>
                    </div>
                 </div>
              </div>

              <div className="flex items-center gap-3 mt-8">
                 {editingIndex !== null && (
                   <button 
                     onClick={deleteCurrentStop}
                     className="p-3.5 rounded-xl border border-red-100 text-red-500 hover:bg-red-50 hover:border-red-200 transition-colors"
                     title="Delete Stop"
                   >
                     <Trash2 className="w-5 h-5" />
                   </button>
                 )}
                 <button 
                   onClick={saveStop}
                   className="flex-1 py-3.5 bg-[#FF385C] text-white rounded-xl font-bold shadow-lg shadow-red-200 hover:bg-[#d9304e] transition-all flex items-center justify-center gap-2"
                 >
                   <Check className="w-5 h-5" />
                   {editingIndex !== null ? 'Save Changes' : 'Add Stop'}
                 </button>
              </div>
           </div>
        </div>
      )}
    </div>
  );
};

import React, { useState, useEffect, useCallback } from 'react';
import { Plus, X, MapPin, Calendar, Clock, Car, Bus, Plane, Shuffle, Search, Minus, Info, Edit2, Check, ChevronDown, ChevronUp, AlertCircle, Sparkles, Trash2, Save, Moon, Locate, LocateFixed } from 'lucide-react';
import { TripFormData, TravelMode, MandatoryStop, ValidationErrors } from '../types';
import { DEFAULT_FORM_DATA } from '../constants';

interface InputFormProps {
  initialData: TripFormData;
  onSubmit: (data: TripFormData, isAlternative: boolean) => void;
  isLoading: boolean;
  validationErrors?: ValidationErrors;
}

const STORAGE_KEY = 'roadTripPro_formData';

const EMPTY_STOP: MandatoryStop = { location: '', date: '', arrivalDate: '', nights: 1 };

// Simulated Database for Autocomplete
const POPULAR_CITIES = [
  "New York, NY", "Los Angeles, CA", "Chicago, IL", "Houston, TX", "Phoenix, AZ",
  "Philadelphia, PA", "San Antonio, TX", "San Diego, CA", "Dallas, TX", "San Jose, CA",
  "Austin, TX", "Jacksonville, FL", "Fort Worth, TX", "Columbus, OH", "San Francisco, CA",
  "Charlotte, NC", "Indianapolis, IN", "Seattle, WA", "Denver, CO", "Washington, DC",
  "Boston, MA", "El Paso, TX", "Nashville, TN", "Detroit, MI", "Oklahoma City, OK",
  "Portland, OR", "Las Vegas, NV", "Memphis, TN", "Louisville, KY", "Baltimore, MD",
  "Milwaukee, WI", "Albuquerque, NM", "Tucson, AZ", "Fresno, CA", "Sacramento, CA",
  "Kansas City, MO", "Mesa, AZ", "Atlanta, GA", "Omaha, NE", "Colorado Springs, CO",
  "Raleigh, NC", "Miami, FL", "Long Beach, CA", "Virginia Beach, VA", "Oakland, CA",
  "Minneapolis, MN", "Tulsa, OK", "Tampa, FL", "Arlington, TX", "New Orleans, LA"
];

export const InputForm: React.FC<InputFormProps> = ({ initialData, onSubmit, isLoading, validationErrors }) => {
  // Initialize state from localStorage or fall back to initialData
  const [formData, setFormData] = useState<TripFormData>(() => {
    try {
      const saved = localStorage.getItem(STORAGE_KEY);
      return saved ? JSON.parse(saved) : initialData;
    } catch (e) {
      console.warn('Failed to load form data from local storage', e);
      return initialData;
    }
  });

  // Modal State
  const [isStopModalOpen, setIsStopModalOpen] = useState(false);
  const [editingIndex, setEditingIndex] = useState<number | null>(null); // null means adding new
  const [tempStop, setTempStop] = useState<MandatoryStop>(EMPTY_STOP);
  const [isLocating, setIsLocating] = useState(false);

  // Autocomplete State
  const [suggestions, setSuggestions] = useState<string[]>([]);
  const [showSuggestions, setShowSuggestions] = useState(false);

  // Persist to localStorage whenever formData changes
  useEffect(() => {
    try {
      localStorage.setItem(STORAGE_KEY, JSON.stringify(formData));
    } catch (e) {
      console.warn('Failed to save form data to local storage', e);
    }
  }, [formData]);

  const handleChange = (field: keyof TripFormData, value: any) => {
    setFormData(prev => ({ ...prev, [field]: value }));
  };

  // --- Geolocation Logic ---
  const performGeolocation = useCallback((isAuto: boolean) => {
    if (!navigator.geolocation) {
      if (!isAuto) alert("Geolocation is not supported by your browser");
      return;
    }

    setIsLocating(true);
    navigator.geolocation.getCurrentPosition(
      (position) => {
        const { latitude, longitude } = position.coords;
        // Format to 4 decimal places for cleanliness
        const locString = `${latitude.toFixed(4)}, ${longitude.toFixed(4)}`;

        // Use setFormData directly to ensure state update
        setFormData(prev => ({ ...prev, origin: locString }));
        setIsLocating(false);
      },
      (error) => {
        console.error("Geolocation error:", error);
        if (!isAuto) {
            alert("Unable to retrieve your location. Please check permissions.");
        }
        setIsLocating(false);
      }
    );
  }, []);

  // Automatic Geolocation on Load
  useEffect(() => {
    // Only attempt to auto-locate if the origin is empty
    if (!formData.origin) {
        performGeolocation(true);
    }
    // eslint-disable-next-line react-hooks/exhaustive-deps
  }, []); // Run only once on mount

  const handleGeolocationClick = () => {
    performGeolocation(false);
  };

  // --- Modal Logic ---

  const openAddStopModal = () => {
    setTempStop({ ...EMPTY_STOP });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(null);
    setIsStopModalOpen(true);
  };

  const openEditStopModal = (index: number) => {
    setTempStop({ ...formData.mandatoryStops[index] });
    setSuggestions([]);
    setShowSuggestions(false);
    setEditingIndex(index);
    setIsStopModalOpen(true);
  };

  const handleTempStopChange = (field: keyof MandatoryStop, value: string | number) => {
