                           type="date" 
                           value={tempStop.arrivalDate || tempStop.date || ''}
                           onChange={(e) => handleTempStopChange('arrivalDate', e.target.value)}
                           className="w-full pl-9 pr-2 py-3 bg-gray-50 border border-gray-200 rounded-xl font-bold text-gray-900 text-xs focus:outline-none focus:border-[#FF385C] focus:bg-white transition-all appearance-none"
