          >
            Logistics & Map
          </button>
        </div>
      </div>

      {/* Content Area */}
      <div className="flex-1 overflow-y-auto bg-gray-50/50 p-4 lg:p-6 scroll-smooth custom-scrollbar">

        {activeTab === 'logistics' ? (
          <div className="max-w-3xl mx-auto space-y-6">
             {/* Navigation Card */}
             <div className="bg-white rounded-xl border border-gray-200 p-6 shadow-sm">
